class LocomotionBase(betterproto2_grpclib.ServiceBase):
    async def drive(
        self, messages: "AsyncIterator[LocomotionCommand]"
    ) -> "LocomotionDriveSummary":
        """
        移動 + 視点制御の client-streaming RPC。stream lifecycle と stateful
        repeater の規約は file header / `LocomotionCommand` 参照。
        """

        raise grpclib.GRPCError(grpclib.const.Status.UNIMPLEMENTED)

    async def reset(
        self, message: "LocomotionResetRequest"
    ) -> "LocomotionResetSummary":
        """
        指定 field を中立値に戻す (Drive stream を中断しない unary)。全 bool
        が false なら全 reset (`LocomotionResetRequest` 参照)。
        """

        raise grpclib.GRPCError(grpclib.const.Status.UNIMPLEMENTED)

    async def __rpc_drive(
        self, stream: "grpclib.server.Stream[LocomotionCommand, LocomotionDriveSummary]"
    ) -> None:
        request = stream.__aiter__()
        response = await self.drive(request)
        await stream.send_message(response)

    async def __rpc_reset(
        self,
        stream: "grpclib.server.Stream[LocomotionResetRequest, LocomotionResetSummary]",
    ) -> None:
        request = await stream.recv_message()
        assert request is not None
        response = await self.reset(request)
        await stream.send_message(response)

    def __mapping__(self) -> "dict[str, grpclib.const.Handler]":
        return {
            "/resonite_io.v1.Locomotion/Drive": grpclib.const.Handler(
                self.__rpc_drive,
                grpclib.const.Cardinality.STREAM_UNARY,
                LocomotionCommand,
                LocomotionDriveSummary,
            ),
            "/resonite_io.v1.Locomotion/Reset": grpclib.const.Handler(
                self.__rpc_reset,
                grpclib.const.Cardinality.UNARY_UNARY,
                LocomotionResetRequest,
                LocomotionResetSummary,
            ),
        }


class MicrophoneBase(betterproto2_grpclib.ServiceBase):
    async def stream_audio(
        self, messages: "AsyncIterator[MicrophoneAudioFrame]"
    ) -> "MicrophoneStreamSummary":
        """
        Python が音声 frame を client-streaming で送信。Bridge は virtual
        AudioInput の ring buffer に append し、engine tick で WriteSamples
        経由で voice 配信ストリームに流す。

        disconnect / lifecycle:
          - `CompleteAsync` で graceful close → Bridge は ring buffer の残りを
            消化し続ける (再生中の余韻を切らない)。
          - UDS 切断 / 例外 cancel → Bridge が ring buffer を clear (RL/ロボティ
            クスの safety: client crash 時に古い音が残らない)。
        """

        raise grpclib.GRPCError(grpclib.const.Status.UNIMPLEMENTED)

    async def __rpc_stream_audio(
        self,
        stream: "grpclib.server.Stream[MicrophoneAudioFrame, MicrophoneStreamSummary]",
    ) -> None:
        request = stream.__aiter__()
        response = await self.stream_audio(request)
        await stream.send_message(response)

    def __mapping__(self) -> "dict[str, grpclib.const.Handler]":
        return {
            "/resonite_io.v1.Microphone/StreamAudio": grpclib.const.Handler(
                self.__rpc_stream_audio,
                grpclib.const.Cardinality.STREAM_UNARY,
                MicrophoneAudioFrame,
                MicrophoneStreamSummary,
            ),
        }


class SessionBase(betterproto2_grpclib.ServiceBase):
    """
    Session は制御プレーンの中心サービス。モダリティ固有の RPC は別 service に
    分割するため、本 service は接続確認と将来的な capability negotiation のみを
    担当する。
    """

    async def ping(self, message: "PingRequest") -> "PingResponse":
        raise grpclib.GRPCError(grpclib.const.Status.UNIMPLEMENTED)

    async def __rpc_ping(
        self, stream: "grpclib.server.Stream[PingRequest, PingResponse]"
    ) -> None:
        request = await stream.recv_message()
        assert request is not None
        response = await self.ping(request)
        await stream.send_message(response)

    def __mapping__(self) -> "dict[str, grpclib.const.Handler]":
        return {
            "/resonite_io.v1.Session/Ping": grpclib.const.Handler(
                self.__rpc_ping,
                grpclib.const.Cardinality.UNARY_UNARY,
                PingRequest,
                PingResponse,
            ),
        }


class SpeakerBase(betterproto2_grpclib.ServiceBase):
    async def stream_audio(
        self, message: "SpeakerStreamRequest"
    ) -> "AsyncIterator[AudioFrame]":
        """
        final mix を server-streaming で push 配信。Bridge が WASAPI audio thread
        からチャネルに push したものを engine 順序保証ありで流す。
        """

        raise grpclib.GRPCError(grpclib.const.Status.UNIMPLEMENTED)
        yield AudioFrame()

    async def __rpc_stream_audio(
        self, stream: "grpclib.server.Stream[SpeakerStreamRequest, AudioFrame]"
    ) -> None:
        request = await stream.recv_message()
        assert request is not None
        await self._call_rpc_handler_server_stream(
            self.stream_audio,
            stream,
            request,
        )

    def __mapping__(self) -> "dict[str, grpclib.const.Handler]":
        return {
            "/resonite_io.v1.Speaker/StreamAudio": grpclib.const.Handler(
                self.__rpc_stream_audio,
                grpclib.const.Cardinality.UNARY_STREAM,
                SpeakerStreamRequest,
                AudioFrame,
            ),
        }
